import React, { useState } from "react";
import { LayoutDashboard, ArrowDownToLine, ArrowUpFromLine, Building2, Settings } from "lucide-react";
import { C, GLOBAL_FONTS_CSS } from "./theme";
import { useFinanceiro } from "./lib/useFinanceiro";
import { storageIsLive } from "./lib/store";
import Dashboard from "./components/Dashboard";
import ContasReceber from "./components/ContasReceber";
import ContasPagar from "./components/ContasPagar";
import CDs from "./components/CDs";
import Ajustes from "./components/Ajustes";
import { Card } from "./components/ui";

const LOGO_SRC = "data:image/png;base64,";

const NAV = [
  { id: "painel", label: "Painel", icon: LayoutDashboard },
  { id: "receber", label: "Receber", icon: ArrowDownToLine },
  { id: "pagar", label: "Pagar", icon: ArrowUpFromLine },
  { id: "cds", label: "CDs", icon: Building2 },
  { id: "ajustes", label: "Ajustes", icon: Settings },
];

export default function App({ contaInfo }) {
  const [tab, setTab] = useState("painel");
  const fin = useFinanceiro();

  return (
    <div style={{ minHeight: "100vh", color: C.text, fontFamily: "'Inter',sans-serif", paddingBottom: 96,
      background: `radial-gradient(1200px 600px at 80% -10%, rgba(43,92,230,.18), transparent 60%), radial-gradient(900px 500px at -10% 10%, rgba(13,29,86,.5), transparent 55%), ${C.bg}` }}>
      <style>{`
        ${GLOBAL_FONTS_CSS}
        *{box-sizing:border-box} ::selection{background:${C.royal};color:#fff}
        select option{background:${C.surface2};color:${C.text}}
        input::placeholder{color:${C.dim}}
        ::-webkit-scrollbar{width:0}
        @media (prefers-reduced-motion: no-preference){
          .pop{animation:pop .4s cubic-bezier(.2,.7,.3,1) both}
          @keyframes pop{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:none}}
        }
      `}</style>

      <header style={{ position: "sticky", top: 0, zIndex: 10,
        background: `linear-gradient(180deg, rgba(13,29,86,.92), rgba(7,12,30,.82))`,
        backdropFilter: "blur(14px)", borderBottom: `1px solid ${C.border}` }}>
        <div style={{ maxWidth: 680, margin: "0 auto", padding: "13px 18px 11px" }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 12 }}>
            <div style={{ background: "#fff", borderRadius: 11, padding: "7px 14px",
              display: "inline-flex", alignItems: "center", boxShadow: "0 3px 14px rgba(0,0,0,.3)" }}>
              <img src={LOGO_SRC} alt="AM Express" style={{ height: 26, objectFit: "contain", display: "block" }} />
            </div>
            <div style={{ textAlign: "right" }}>
              <div style={{ fontSize: 10, color: C.sky, letterSpacing: ".16em", textTransform: "uppercase", fontWeight: 700 }}>Financeiro</div>
              <div style={{ fontSize: 11, color: C.muted, fontFamily: "'JetBrains Mono',monospace" }}>
                {contaInfo?.email || "Operação"}</div>
            </div>
          </div>
        </div>
      </header>

      <main style={{ maxWidth: 680, margin: "0 auto", padding: 16 }}>
        {!storageIsLive() && (
          <Card style={{ marginBottom: 14, borderColor: C.royal }}>
            <div style={{ fontSize: 13, color: C.sky }}>
              Salvamento automático indisponível neste ambiente — dados só nesta sessão. No app publicado,
              isto sincroniza via Firebase entre você e a Catrine.
            </div>
          </Card>
        )}
        {!fin.loaded ? null : (
          <>
            {tab === "painel" && <Dashboard fin={fin} />}
            {tab === "receber" && <ContasReceber fin={fin} />}
            {tab === "pagar" && <ContasPagar fin={fin} />}
            {tab === "cds" && <CDs fin={fin} />}
            {tab === "ajustes" && <Ajustes fin={fin} contaInfo={contaInfo} />}
          </>
        )}
      </main>

      <nav style={{ position: "fixed", bottom: 0, left: 0, right: 0, zIndex: 20,
        background: "rgba(7,12,30,.85)", backdropFilter: "blur(16px)", borderTop: `1px solid ${C.border}` }}>
        <div style={{ maxWidth: 680, margin: "0 auto", display: "flex", padding: "6px 6px 10px" }}>
          {NAV.map((n) => {
            const on = tab === n.id;
            return (
              <button key={n.id} onClick={() => setTab(n.id)} style={{ flex: 1, background: "none", border: "none",
                cursor: "pointer", padding: "8px 2px", display: "flex", flexDirection: "column", alignItems: "center",
                gap: 4, color: on ? "#fff" : C.dim }}>
                <div style={{ padding: "5px 14px", borderRadius: 11, transition: ".2s",
                  background: on ? `linear-gradient(135deg,${C.sky},${C.royalDeep})` : "transparent" }}>
                  <n.icon size={18} strokeWidth={on ? 2.5 : 2} />
                </div>
                <span style={{ fontSize: 9.5, fontWeight: on ? 700 : 500 }}>{n.label}</span>
              </button>
            );
          })}
        </div>
      </nav>
    </div>
  );
}
